import Message from '../components/Message';

const CartScreen = ({ cartItems, onRemove, onCheckout }) => {
  const totalDays = cartItems.reduce((sum, item) => sum + item.days, 0);

  return (
    <section className="cart-layout">
      <div>
        <h1>Korpa za razmenu</h1>
        {cartItems.length === 0 ? (
          <Message>Korpa je prazna. Vrati se na pocetnu i izaberi knjigu.</Message>
        ) : (
          <div className="cart-list">
            {cartItems.map((item) => (
              <article key={item.id}>
                <img src={item.image} alt={item.name} />
                <div>
                  <strong>{item.name}</strong>
                  <span>{item.author}</span>
                </div>
                <span>{item.days} dana</span>
                <button type="button" onClick={() => onRemove(item.id)}>
                  Obrisi
                </button>
              </article>
            ))}
          </div>
        )}
      </div>
      <aside className="summary-card">
        <h2>Ukupno: {cartItems.length} knjiga</h2>
        <p>Predvidjeno trajanje razmene: {totalDays} dana</p>
        <button disabled={cartItems.length === 0} type="button" onClick={onCheckout}>
          Nastavi razmenu
        </button>
      </aside>
    </section>
  );
};

export default CartScreen;
